fn solve(nums: Vec<i64>) -> i64 {
    if nums.len() < 4 {
        return 0;
    }

    let n = nums.len();
    let mut max_sum = i64::MIN;

    // Precompute for each position the longest increasing and decreasing sequences
    let mut inc = vec![0; n];
    let mut dec = vec![0; n];

    // Compute increasing sequences from left to right
    inc[0] = 1;
    for i in 1..n {
        if nums[i] > nums[i - 1] {
            inc[i] = inc[i - 1] + 1;
        } else {
            inc[i] = 1;
        }
    }

    // Compute decreasing sequences from right to left
    dec[n - 1] = 1;
    for i in (0..n - 1).rev() {
        if nums[i] > nums[i + 1] {
            dec[i] = dec[i + 1] + 1;
        } else {
            dec[i] = 1;
        }
    }

    // Check all possible triplets (l, p, q, r)
    for l in 0..n {
        for p in l + 1..n {
            if nums[p] <= nums[p - 1] {
                continue;
            }
            for q in p + 1..n {
                if nums[q] >= nums[q - 1] {
                    continue;
                }
                for r in q + 1..n {
                    if nums[r] <= nums[r - 1] {
                        continue;
                    }
                    let sum = nums[l..r + 1].iter().sum::<i64>();
                    max_sum = std::cmp::max(max_sum, sum);
                }
            }
        }
    }

    max_sum
}
